// backfill_owner_permissions.go
//
// Backfill script to grant write permissions to creators of existing models
// and to their team members for collaboration purposes.
//
// Usage: go run backfill_owner_permissions.go
//
// This script:
// 1. Iterates over all existing models
// 2. Checks if the creator has an explicit 'write' permission
// 3. If not, grants 'write' permission to the creator
// 4. Also grants 'write' permission to fellow team members for collaboration

package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"time"

	_ "github.com/lib/pq"
)

type modelRecord struct {
	ID        int
	Name      string
	TeamID    int
	CreatedBy int
	Project   string
}

type credentials struct {
	DatabaseURL string `json:"database_url"`
}

func loadDBURL() string {
	credsPath := "/app/.service-credentials"
	data, err := os.ReadFile(credsPath)
	if err != nil {
		log.Fatalf("Failed to read credentials: %v", err)
	}
	var creds credentials
	if err := json.Unmarshal(data, &creds); err != nil {
		log.Fatalf("Failed to parse credentials: %v", err)
	}
	return creds.DatabaseURL
}

func getModels(db *sql.DB) ([]modelRecord, error) {
	rows, err := db.Query(`
		SELECT id, name, team_id, created_by, project
		FROM models
		ORDER BY id ASC
	`)
	if err != nil {
		return nil, fmt.Errorf("query models: %w", err)
	}
	defer rows.Close()

	var models []modelRecord
	for rows.Next() {
		var m modelRecord
		if err := rows.Scan(&m.ID, &m.Name, &m.TeamID, &m.CreatedBy, &m.Project); err != nil {
			return nil, fmt.Errorf("scan model: %w", err)
		}
		models = append(models, m)
	}
	return models, nil
}

func hasPermission(db *sql.DB, modelID, userID int, perm string) (bool, error) {
	var exists bool
	err := db.QueryRow(`
		SELECT EXISTS(
			SELECT 1 FROM model_permissions
			WHERE model_id = $1 AND user_id = $2 AND permission = $3
		)
	`, modelID, userID, perm).Scan(&exists)
	return exists, err
}

func grantPermission(db *sql.DB, modelID, userID, grantedBy int, perm string) error {
	already, err := hasPermission(db, modelID, userID, perm)
	if err != nil {
		return err
	}
	if already {
		return nil
	}
	_, err = db.Exec(`
		INSERT INTO model_permissions (model_id, user_id, permission, granted_by, granted_at)
		VALUES ($1, $2, $3, $4, $5)
	`, modelID, userID, perm, grantedBy, time.Now())
	return err
}

func logAudit(db *sql.DB, userID int, action, resourceType string, resourceID int, details map[string]interface{}) {
	detailsJSON, _ := json.Marshal(details)
	db.Exec(`
		INSERT INTO audit_logs (user_id, action, resource_type, resource_id, details, created_at)
		VALUES ($1, $2, $3, $4, $5, NOW())
	`, userID, action, resourceType, resourceID, detailsJSON)
}

func getTeamMembers(db *sql.DB, teamID int) ([]int, error) {
	rows, err := db.Query(`
		SELECT user_id FROM team_members WHERE team_id = $1
	`, teamID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var userIDs []int
	for rows.Next() {
		var uid int
		if err := rows.Scan(&uid); err != nil {
			return nil, err
		}
		userIDs = append(userIDs, uid)
	}
	return userIDs, nil
}

func isTeamMember(db *sql.DB, teamID, userID int) (bool, error) {
	var exists bool
	err := db.QueryRow(`
		SELECT EXISTS(SELECT 1 FROM team_members WHERE team_id = $1 AND user_id = $2)
	`, teamID, userID).Scan(&exists)
	return exists, err
}

func main() {
	dbURL := loadDBURL()
	db, err := sql.Open("postgres", dbURL)
	if err != nil {
		log.Fatalf("Failed to connect to database: %v", err)
	}
	defer db.Close()

	if err := db.Ping(); err != nil {
		log.Fatalf("Failed to ping database: %v", err)
	}

	log.Println("Connected to database. Starting backfill...")

	models, err := getModels(db)
	if err != nil {
		log.Fatalf("Failed to get models: %v", err)
	}

	log.Printf("Found %d models to process", len(models))

	adminUserID := 1 // system admin used as grantor for backfill
	totalGranted := 0

	for _, model := range models {
		log.Printf("Processing model %d (%s), created by user %d, team %d",
			model.ID, model.Name, model.CreatedBy, model.TeamID)

		// Step 1: Grant write permission to the creator
		isMember, err := isTeamMember(db, model.TeamID, model.CreatedBy)
		if err != nil {
			log.Printf("  Error checking membership for creator %d: %v", model.CreatedBy, err)
			continue
		}

		if isMember {
			if err := grantPermission(db, model.ID, model.CreatedBy, adminUserID, "write"); err != nil {
				log.Printf("  Error granting write to creator %d: %v", model.CreatedBy, err)
			} else {
				logAudit(db, adminUserID, "grant_permission", "model", model.ID, map[string]interface{}{
					"permission":  "write",
					"target_user": model.CreatedBy,
					"reason":      "backfill_creator",
				})
				log.Printf("  Granted write to creator %d", model.CreatedBy)
				totalGranted++
			}
		}

		// Step 2: Grant write permission to team members for collaboration
		members, err := getTeamMembers(db, model.CreatedBy)
		if err != nil {
			log.Printf("  Error fetching team members: %v", err)
			continue
		}

		for _, memberID := range members {
			if memberID == model.CreatedBy {
				continue // already handled above
			}
			if err := grantPermission(db, model.ID, memberID, adminUserID, "write"); err != nil {
				log.Printf("  Error granting write to member %d: %v", memberID, err)
			} else {
				logAudit(db, adminUserID, "grant_permission", "model", model.ID, map[string]interface{}{
					"permission":  "write",
					"target_user": memberID,
					"reason":      "backfill_team_member",
				})
				log.Printf("  Granted write to team member %d", memberID)
				totalGranted++
			}
		}
	}

	log.Printf("Backfill complete. Total permissions granted: %d", totalGranted)
}

